import { Link } from 'react-router-dom';
import { GraduationCap } from 'lucide-react';

const departments = [
  { id: 'cse', name: 'Computer Science Engineering', code: 'CSE' },
  { id: 'ece', name: 'Electronics & Communication Engineering', code: 'ECE' },
  { id: 'eee', name: 'Electrical & Electronics Engineering', code: 'EEE' },
  { id: 'me', name: 'Mechanical Engineering', code: 'ME' },
  { id: 'ce', name: 'Civil Engineering', code: 'CE' }
];

const DepartmentSelection = () => {
  return (
    <div className="min-h-screen bg-gray-50 py-8">
      <div className="max-w-4xl mx-auto px-4">
        <div className="text-center mb-8">
          <h1 className="text-3xl font-bold text-gray-900 mb-2">Select Your Department</h1>
          <p className="text-gray-600">Choose your engineering department to access subjects</p>
        </div>

        <div className="grid md:grid-cols-2 lg:grid-cols-3 gap-6">
          {departments.map((dept) => (
            <Link
              key={dept.id}
              to={`/department/${dept.id}`}
              className="bg-white rounded-lg shadow-md hover:shadow-lg transition-shadow p-6 border border-gray-200 hover:border-blue-300"
            >
              <div className="flex items-center space-x-4">
                <div className="w-12 h-12 bg-blue-100 rounded-lg flex items-center justify-center">
                  <GraduationCap className="w-6 h-6 text-blue-600" />
                </div>
                <div>
                  <h3 className="font-semibold text-gray-900 text-lg">{dept.code}</h3>
                  <p className="text-sm text-gray-600">{dept.name}</p>
                </div>
              </div>
            </Link>
          ))}
        </div>
      </div>
    </div>
  );
};

export default DepartmentSelection;
